import pyotp
import qrcode
import base64
import time
from datetime import datetime, timedelta

class TOTPAuthenticator:
    def __init__(self, issuer_name="MyApp", account_name_prefix="User"):
        self.issuer_name = issuer_name
        self.account_name_prefix = account_name_prefix
        self.user_secrets = {} # Store user_id -> secret

    def generate_secret(self, user_id):
        """Generates a new TOTP secret for a given user."""
        secret = pyotp.random_base32()
        self.user_secrets[user_id] = secret
        return secret

    def get_provisioning_uri(self, user_id, secret=None):
        """
        Generates the provisioning URI (otpauth://) for a user.
        If secret is not provided, it fetches from stored secrets.
        """
        if secret is None:
            secret = self.user_secrets.get(user_id)
            if secret is None:
                raise ValueError(f"No secret found for user_id: {user_id}. Generate one first.")

        account_name = f"{self.account_name_prefix}:{user_id}"
        uri = pyotp.TOTP(secret).provisioning_uri(
            name=account_name,
            issuer_name=self.issuer_name
        )
        return uri

    def generate_qr_code(self, user_id, secret=None):
        """
        Generates a QR code image (as base64 string) for the user to scan.
        Returns a tuple: (secret, base64_image_string)
        """
        if secret is None:
            secret = self.user_secrets.get(user_id)
            if secret is None:
                raise ValueError(f"No secret found for user_id: {user_id}. Generate one first.")

        uri = self.get_provisioning_uri(user_id, secret)
        
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(uri)
        qr.make(fit=True)

        img = qr.make_image(fill_color="black", back_color="white")
        
        # Convert PIL Image to base64 string
        import io
        buffered = io.BytesIO()
        img.save(buffered, format="PNG")
        img_str = base64.b64encode(buffered.getvalue()).decode("utf-8")
        
        return secret, img_str

    def verify_totp(self, user_id, user_code, window=1):
        """
        Verifies a user-provided TOTP code against the stored secret.
        
        Args:
            user_id (str): The ID of the user.
            user_code (str): The TOTP code provided by the user.
            window (int): The number of time steps (30-second intervals) to check
                          before and after the current time. Default is 1,
                          meaning it checks current step, step -1, and step +1.
                          A window of 0 means only the current step is checked.
                          
        Returns:
            bool: True if the code is valid, False otherwise.
        """
        secret = self.user_secrets.get(user_id)
        if secret is None:
            print(f"Error: No secret found for user_id: {user_id}.")
            return False

        totp = pyotp.TOTP(secret)
        
        # Verify with a window to account for clock skew
        is_valid = totp.verify(user_code, valid_window=window)
        return is_valid

    def get_current_totp_code(self, user_id):
        """
        Calculates and returns the current expected TOTP code for a user.
        Useful for testing or debugging.
        """
        secret = self.user_secrets.get(user_id)
        if secret is None:
            print(f"Error: No secret found for user_id: {user_id}.")
            return None
        
        totp = pyotp.TOTP(secret)
        return totp.now()

